from collections import Counter

class Solution(object):
    def maxPalindromesAfterOperations(self, words):
        # Count total frequency of all characters
        freq = Counter()
        for w in words:
            freq.update(w)

        # Total pairs available
        pairs = sum(v // 2 for v in freq.values())

        # Sort words by length (greedy: fill shortest first)
        lengths = sorted(len(w) for w in words)

        count = 0
        for length in lengths:
            needed = length // 2  # pairs needed for this word
            if pairs >= needed:
                pairs -= needed
                count += 1
            else:
                break  # can't fill this or any longer word
        return count
